699	func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
700		if projectRoot == "" {
701			return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
702		}
703		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
704		if len(normalized) == 0 {
705			return nil, fmt.Errorf("no dirty implementation paths to preserve")
706		}
707	
708		var preserved *PreDispatchDirtyPreservation
709		if err := withTrackerLock(projectRoot, func() error {
710			var err error
711			preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
712			return err
713		}); err != nil {
714			return nil, err
715		}
716		return preserved, nil
717	}
