// TestTrackerLock_SectionInSample asserts that withMainGitLock with a specific
// section string yields a TrackerLockSample carrying that section.
func TestTrackerLock_SectionInSample(t *testing.T) {
	root := initTrackerRepo(t)

	var mu sync.Mutex
	var captured []TrackerLockSample
	prev := TrackerLockMetricsSink
	TrackerLockMetricsSink = func(s TrackerLockSample) {
		mu.Lock()
		captured = append(captured, s)
		mu.Unlock()
	}
	defer func() { TrackerLockMetricsSink = prev }()

	err := withMainGitLock(root, "durable_audit", func() error { return nil })
	require.NoError(t, err)

	mu.Lock()
	got := append([]TrackerLockSample(nil), captured...)
	mu.Unlock()

	if len(got) == 0 {
		t.Fatal("TrackerLockMetricsSink was not called")
	}
	if got[0].Section != "durable_audit" {
		t.Fatalf("Section = %q, want %q", got[0].Section, "durable_audit")
	}
}

// TestTrackerLock_WorkerSinkEmitsLogAndEvent asserts that the worker-installed
// sink (as wired in ExecuteBeadLoopRuntime.Run) emits both a loop.tracker_lock
// event and a plain log line per acquire/release, carrying section, wait, hold,
// and retries.
func TestTrackerLock_WorkerSinkEmitsLogAndEvent(t *testing.T) {
	root := initTrackerRepo(t)

	// Collect emitted events and log output, simulating the worker sink install.
	var eventsMu sync.Mutex
	type capturedEvent struct {
		kind string
		data map[string]any
	}
	var events []capturedEvent
	var logBuf strings.Builder

	emitFn := func(kind string, data map[string]any) {
		eventsMu.Lock()
		events = append(events, capturedEvent{kind: kind, data: data})
		eventsMu.Unlock()
	}
	logWriter := &logBuf

	// Simulate the worker sink install from execute_bead_loop.go Run().
	prev := TrackerLockMetricsSink
	TrackerLockMetricsSink = func(s TrackerLockSample) {
		emitFn("loop.tracker_lock", map[string]any{
			"section": s.Section,
			"wait":    s.Wait.String(),
			"hold":    s.Hold.String(),
			"retries": s.Retries,
		})
		_, _ = fmt.Fprintf(logWriter, "tracker_lock section=%s wait=%s hold=%s retries=%d\n",
			s.Section, s.Wait, s.Hold, s.Retries)
	}
	defer func() { TrackerLockMetricsSink = prev }()

	err := withMainGitLock(root, "pre_dispatch", func() error { return nil })
	require.NoError(t, err)

	eventsMu.Lock()
	got := append([]capturedEvent(nil), events...)
	eventsMu.Unlock()

	// Verify loop.tracker_lock event was emitted with all four fields.
	var lockEvent *capturedEvent
	for i := range got {
		if got[i].kind == "loop.tracker_lock" {
			lockEvent = &got[i]
			break
		}
	}
	if lockEvent == nil {
		t.Fatal("loop.tracker_lock event was not emitted")
	}
	if lockEvent.data["section"] != "pre_dispatch" {
		t.Fatalf("event section = %v, want %q", lockEvent.data["section"], "pre_dispatch")
	}
	if _, ok := lockEvent.data["wait"]; !ok {
		t.Fatal("event missing 'wait' field")
	}
	if _, ok := lockEvent.data["hold"]; !ok {
		t.Fatal("event missing 'hold' field")
	}
	if _, ok := lockEvent.data["retries"]; !ok {
		t.Fatal("event missing 'retries' field")
	}

	// Verify plain-text log line contains all four fields.
	logLine := logBuf.String()
	for _, want := range []string{"section=pre_dispatch", "wait=", "hold=", "retries="} {
		if !strings.Contains(logLine, want) {
			t.Fatalf("log line missing %q; got: %q", want, logLine)
		}
	}
}

